SELECT * FROM (SELECT num, writer, passwd, subject, content, readCnt, ref,
 ref_step, ref_level, reg_date, ip, rownum rnum FROM (SELECT * FROM board ORDER BY ref DESC, ref_step ASC))
WHERE rnum >= #{start} AND rnum <= #{end}


SELECT NVL(MIN(ref_step), 0)
FROM board
WHERE ref = #{ref}
  AND ref_step > #{ref_step}
  AND ref_level <= #{ref_level}
